const NEEDLES = [/ignore (all )?previous instructions/i, /reveal your (full )?system prompt/i, /игнорируй.*инструкции/i];
for (const el of document.querySelectorAll('*')) {
  const hay = [el.textContent, el.title, el.getAttribute('aria-label'), el.getAttribute('alt')].filter(Boolean).join(' ');
  if (NEEDLES.some((re) => re.test(hay))) flag(el);
}
